export function getArticleBySlug(slug: string): BlogArticle | undefined {
  return blogArticles.find(a => a.slug === slug);
}

export function getArticlesByCity(city: string): BlogArticle[] {
  return blogArticles.filter(a => a.city === city);
}

export function getArticlesByCategory(category: string): BlogArticle[] {
  return blogArticles.filter(a => a.category === category);
}

export function getAllCities(): string[] {
  const cities = new Set(blogArticles.map(a => a.city).filter(Boolean) as string[]);
  return Array.from(cities);
}

export function getAllCategories(): { slug: string; title: string }[] {
  const seen = new Set<string>();
  return blogArticles.filter(a => {
    if (seen.has(a.category)) return false;
    seen.add(a.category);
    return true;
  }).map(a => ({ slug: a.category, title: a.categoryTitle }));
}
